Input {
 // This is an AI brain that can plug to any hardware controller
 schema_version: 1,
 manifest: {
 name: "robot_brain",
 tag: "0.1.0",
 language: "python"
 },
 process: {
 add_cmd: ["uv", "sync"],
 start_cmd: ["uv", "run", "src/main.py"]
 },
 parameters: {},
 interfaces: {
 exposes: {},
 subscribes_to: {
 // The brain receives inputs from sensors
 topics: [
 {
 id: "camera_stream",
 node: "uvc_camera",
 name: "video_stream",
 tag: "0.1.0",
 },
 {
 id: "lidar_sensor",
 node: "rplidar",
 name: "scan",
 tag: "0.1.0",
 },
 ],
 // And emit actions to the controller
 actions: [
 {
 id: "move_right_arm_action",
 node: "openarm01_controller",
 name: "move_right_arm",
 tag: "0.1.0",
 },
 {
 id: "move_left_arm_action",
 node: "openarm01_controller",
 name: "move_left_arm",
 tag: "0.1.0",
 }
 ]
 },
 }
